Great question! Error handling setup is critical, but leaving debug mode enabled in production is a serious security vulnerability that exposes sensitive application internals to attackers.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Debug mode always enabled
app.set('env', 'development');

app.get('/api/user/:id', async (req, res) => {
  const userId = req.params.id;
  // Simulated database query that might fail
  const user = await db.query(`SELECT * FROM users WHERE id = ${userId}`);
  res.json(user);
});

// VULNERABLE: Detailed error handler exposes everything
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    error: err.message,
    stack: err.stack,
    query: err.sql,  // Exposes SQL queries!
    config: {
      database: process.env.DB_HOST,
      secret: process.env.JWT_SECRET  // Exposes secrets!
    }
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Attack Payload**:
```bash
# Trigger error to extract sensitive information
curl "http://target.com/api/user/invalid'OR'1'='1"

# Response exposes internal details:
# {
#   "error": "ER_PARSE_ERROR: You have an error in your SQL syntax...",
#   "stack": "Error: at Query... at /var/www/app/node_modules/mysql/...",
#   "query": "SELECT * FROM users WHERE id = invalid'OR'1'='1",
#   "config": {
#     "database": "prod-db.internal.company.com",
#     "secret": "super-secret-jwt-key-2024"
#   }
# }
```

**Why This Is Dangerous**:
- Stack traces reveal file paths, dependencies, and application structure
- SQL queries in errors enable SQL injection refinement
- Environment variables like JWT_SECRET allow token forgery
- Internal hostnames help attackers map network topology
- Dependency versions reveal known CVEs to exploit

**SECURE VERSION**:

```javascript
const express = require('express');
const winston = require('winston');
const app = express();

// SECURE: Environment-based configuration
const isProduction = process.env.NODE_ENV === 'production';

// Configure secure logging
const logger = winston.createLogger({
  level: isProduction ? 'error' : 'debug',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

app.get('/api/user/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);
    if (isNaN(userId)) {
      return res.status(400).json({ error: 'Invalid user ID format' });
    }
    const user = await db.query('SELECT id, name, email FROM users WHERE id = ?', [userId]);
    res.json(user);
  } catch (err) {
    next(err);
  }
});

// SECURE: Environment-aware error handler
app.use((err, req, res, next) => {
  // Generate unique error ID for correlation
  const errorId = crypto.randomUUID();

  // Log full details internally (never to client)
  logger.error({
    errorId,
    message: err.message,
    stack: err.stack,
    url: req.url,
    method: req.method,
    ip: req.ip,
    timestamp: new Date().toISOString()
  });

  // Return sanitized response to client
  if (isProduction) {
    res.status(500).json({
      error: 'An unexpected error occurred',
      errorId: errorId  // For support reference only
    });
  } else {
    // Development only - never in production
    res.status(500).json({
      error: err.message,
      stack: err.stack
    });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Environment detection**: NODE_ENV determines error verbosity
- **Error ID correlation**: Unique IDs let support trace issues without exposing details
- **Internal logging**: Full details logged server-side, sanitized response to client
- **No sensitive data in responses**: Secrets, paths, and queries never sent to client

Excellent follow-up! Debug information can leak from many sources beyond just error handlers. In production applications, you need comprehensive controls across the entire stack.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const winston = require('winston');
const expressWinston = require('express-winston');
const crypto = require('crypto');

const app = express();

// Environment configuration with validation
const config = {
  isProduction: process.env.NODE_ENV === 'production',
  logLevel: process.env.LOG_LEVEL || 'info',
  trustedProxies: process.env.TRUSTED_PROXIES?.split(',') || []
};

// Validate production requirements
if (config.isProduction) {
  const requiredVars = ['NODE_ENV', 'SESSION_SECRET', 'DB_HOST'];
  const missing = requiredVars.filter(v => !process.env[v]);
  if (missing.length > 0) {
    console.error(`Missing required env vars: ${missing.join(', ')}`);
    process.exit(1);
  }
}

// LAYER 1: Security headers to prevent information leakage
app.use(helmet({
  hidePoweredBy: true,  // Remove X-Powered-By header
  hsts: config.isProduction ? { maxAge: 31536000, includeSubDomains: true } : false
}));

// LAYER 2: Remove server identification
app.disable('x-powered-by');
app.set('env', config.isProduction ? 'production' : 'development');

// LAYER 3: Request logging (sanitized)
const sanitizeHeaders = (req) => {
  const headers = { ...req.headers };
  const sensitiveHeaders = ['authorization', 'cookie', 'x-api-key'];
  sensitiveHeaders.forEach(h => {
    if (headers[h]) headers[h] = '[REDACTED]';
  });
  return headers;
};

const logger = winston.createLogger({
  level: config.logLevel,
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'api-service' },
  transports: config.isProduction ? [
    new winston.transports.File({ filename: '/var/log/app/error.log', level: 'error' }),
    new winston.transports.File({ filename: '/var/log/app/combined.log' })
  ] : [
    new winston.transports.Console({ format: winston.format.simple() })
  ]
});

// Request logging middleware
app.use(expressWinston.logger({
  winstonInstance: logger,
  meta: true,
  expressFormat: true,
  requestFilter: (req, propName) => {
    if (propName === 'headers') return sanitizeHeaders(req);
    if (propName === 'body' && req.body?.password) {
      return { ...req.body, password: '[REDACTED]' };
    }
    return req[propName];
  }
}));

// LAYER 4: Custom response wrapper to prevent accidental leaks
const secureResponse = (req, res, next) => {
  const originalJson = res.json.bind(res);

  res.json = (data) => {
    if (config.isProduction && data) {
      // Remove any accidentally included sensitive fields
      const sanitized = JSON.parse(JSON.stringify(data));
      const sensitiveKeys = ['password', 'secret', 'token', 'apiKey', 'stack', 'sql'];

      const removeSensitive = (obj) => {
        if (typeof obj !== 'object' || obj === null) return obj;
        Object.keys(obj).forEach(key => {
          if (sensitiveKeys.some(k => key.toLowerCase().includes(k))) {
            delete obj[key];
          } else if (typeof obj[key] === 'object') {
            removeSensitive(obj[key]);
          }
        });
        return obj;
      };

      return originalJson(removeSensitive(sanitized));
    }
    return originalJson(data);
  };
  next();
};

app.use(secureResponse);

// LAYER 5: Catch-all 404 handler (no path disclosure)
app.use((req, res, next) => {
  res.status(404).json({ error: 'Resource not found' });
});

// LAYER 6: Global error handler with monitoring integration
app.use((err, req, res, next) => {
  const errorId = crypto.randomUUID();
  const errorContext = {
    errorId,
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    userId: req.user?.id || 'anonymous'
  };

  // Categorize error severity
  const isOperationalError = err.isOperational || err.statusCode < 500;

  if (isOperationalError) {
    logger.warn({ ...errorContext, message: err.message, type: 'operational' });
  } else {
    // Critical error - full logging + alerting
    logger.error({
      ...errorContext,
      message: err.message,
      stack: err.stack,
      type: 'critical'
    });

    // Alert on critical errors (integrate with PagerDuty/Slack)
    if (config.isProduction) {
      // alertService.critical(errorId, err);
    }
  }

  // Client response
  const statusCode = err.statusCode || 500;
  const response = config.isProduction
    ? { error: statusCode < 500 ? err.message : 'Internal server error', errorId }
    : { error: err.message, stack: err.stack, errorId };

  res.status(statusCode).json(response);
});

// Health check endpoint (sanitized)
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString()
    // Never include: version, dependencies, memory usage in production
  });
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **Security Headers (helmet)**:
```javascript
// Removes server fingerprinting
app.use(helmet({ hidePoweredBy: true }));
app.disable('x-powered-by');
// Attacker can't identify Express version
```

2. **Response Sanitization**:
```javascript
// Automatically strips sensitive fields from ALL responses
const sanitized = removeSensitive(responseData);
// Even if developer accidentally includes 'password' field, it's removed
```

3. **Structured Logging with Redaction**:
```javascript
// Logs everything for debugging, but redacts secrets
if (headers['authorization']) headers['authorization'] = '[REDACTED]';
// Audit trail exists without credential exposure
```

**Additional Protections**:

- **Environment validation at startup**: Application fails fast if production config is incomplete
- **Error ID correlation**: Support can trace issues using errorId without exposing internals
- **Operational vs critical errors**: Different handling and alerting based on severity
- **Source maps disabled in production**: Never deploy .map files that reveal original source
- **GraphQL introspection disabled**: `introspection: process.env.NODE_ENV !== 'production'`
- **Swagger/API docs restricted**: Only available in development or behind authentication

**Configuration Checklist**:
```javascript
// package.json scripts
"scripts": {
  "start": "NODE_ENV=production node server.js",
  "dev": "NODE_ENV=development nodemon server.js"
}

// .env.production (example - use secrets manager in real prod)
NODE_ENV=production
LOG_LEVEL=error
DEBUG=  # Empty - no debug output
```

Debug mode in production is a critical security misconfiguration that has led to numerous breaches. In 2023, exposed Spring Boot Actuator endpoints led to credential theft at multiple organizations, with one financial services company suffering $2.3M in cloud resource fraud after AWS keys were extracted from heap dumps.

**VULNERABLE CODE**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.web.servlet.config.annotation.CorsRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@SpringBootApplication
public class InsecureApplication {

    public static void main(String[] args) {
        // VULNERABLE: Running with debug enabled
        System.setProperty("spring.profiles.active", "dev");
        SpringApplication.run(InsecureApplication.class, args);
    }

    @Bean
    public WebMvcConfigurer corsConfigurer() {
        return new WebMvcConfigurer() {
            @Override
            public void addCorsMappings(CorsRegistry registry) {
                // VULNERABLE: Allow all origins
                registry.addMapping("/**").allowedOrigins("*");
            }
        };
    }
}
```

```properties
