**Attack Payload**:
```bash
# Discover exposed actuator endpoints
curl https://target.com/actuator

# Extract environment variables including database credentials
curl https://target.com/actuator/env

# Download heap dump containing in-memory secrets
curl https://target.com/actuator/heapdump -o heapdump.hprof

# Analyze heap dump for credentials
jhat heapdump.hprof
# Or use Eclipse Memory Analyzer to search for "password", "secret", "key"

# Trigger remote shutdown if enabled
curl -X POST https://target.com/actuator/shutdown
```

**Why This Is Dangerous**:
- Actuator endpoints expose sensitive environment variables, database credentials, and API keys
- Heap dumps contain all in-memory data including decrypted secrets and session tokens
- Detailed error messages reveal internal architecture, file paths, and database schema
- Debug logging may capture passwords, credit cards, and PII in log files
- Permissive CORS allows any website to make authenticated requests to your API

**SECURE VERSION**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Profile;
import org.springframework.web.servlet.config.annotation.CorsRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@SpringBootApplication
public class SecureApplication {

    public static void main(String[] args) {
        SpringApplication app = new SpringApplication(SecureApplication.class);
        // Profile is set via environment variable, not hardcoded
        app.run(args);
    }

    @Bean
    @Profile("production")
    public WebMvcConfigurer productionCorsConfigurer() {
        return new WebMvcConfigurer() {
            @Override
            public void addCorsMappings(CorsRegistry registry) {
                // SECURE: Explicit allowed origins only
                registry.addMapping("/api/**")
                    .allowedOrigins("https://app.example.com", "https://admin.example.com")
                    .allowedMethods("GET", "POST", "PUT", "DELETE")
                    .allowCredentials(true)
                    .maxAge(3600);
            }
        };
    }
}
```

```properties
# application-production.properties - SECURE CONFIGURATION
server.port=8443
server.ssl.enabled=true

# SECURE: Minimal actuator exposure
management.endpoints.web.exposure.include=health,info,metrics
management.endpoint.health.show-details=when-authorized
management.endpoint.env.enabled=false
management.endpoint.heapdump.enabled=false
management.endpoint.shutdown.enabled=false

# SECURE: Actuator on separate port with authentication
management.server.port=9090
management.server.address=127.0.0.1

# SECURE: No sensitive error details
server.error.include-message=never
server.error.include-stacktrace=never
server.error.include-binding-errors=never

# SECURE: Production logging level
logging.level.root=WARN
logging.level.org.springframework=WARN
logging.level.com.example=INFO

# SECURE: Credentials from environment/secrets manager
spring.datasource.url=${DB_URL}
spring.datasource.username=${DB_USERNAME}
spring.datasource.password=${DB_PASSWORD}
```

**Key Security Controls**:
- **Minimal Actuator Exposure**: Only health, info, and metrics endpoints exposed - no env, heapdump, or shutdown
- **Separate Management Port**: Actuator endpoints on internal-only port (9090) bound to localhost
- **Error Suppression**: Stack traces and detailed errors hidden in production responses
- **External Secret Management**: Database credentials loaded from environment variables or secrets manager, never in config files
- **Explicit CORS Policy**: Only specific trusted origins allowed with credentials

Excellent question! Production security requires authenticated actuator access, proper security headers, environment-specific configuration, and defense in depth. Here's a comprehensive production-ready setup:

**PRODUCTION PATTERN**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.annotation.Order;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.provisioning.InMemoryUserDetailsManager;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter;
import org.springframework.boot.actuate.autoconfigure.security.servlet.EndpointRequest;
import org.springframework.boot.actuate.health.HealthEndpoint;
import org.springframework.boot.actuate.info.InfoEndpoint;

@SpringBootApplication
public class ProductionSecureApplication {

    public static void main(String[] args) {
        // Validate we're not accidentally running dev profile in production
        String profile = System.getenv("SPRING_PROFILES_ACTIVE");
        String environment = System.getenv("ENVIRONMENT");

        if ("production".equals(environment) && "dev".equals(profile)) {
            throw new IllegalStateException(
                "SECURITY VIOLATION: Cannot run dev profile in production environment");
        }

        SpringApplication.run(ProductionSecureApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class SecurityConfiguration {

    // Separate security chain for actuator endpoints
    @Bean
    @Order(1)
    public SecurityFilterChain actuatorSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .securityMatcher(EndpointRequest.toAnyEndpoint())
            .authorizeHttpRequests(authorize -> authorize
                // Health and info are public for load balancer checks
                .requestMatchers(EndpointRequest.to(HealthEndpoint.class, InfoEndpoint.class))
                    .permitAll()
                // All other actuator endpoints require ACTUATOR_ADMIN role
                .anyRequest().hasRole("ACTUATOR_ADMIN")
            )
            .httpBasic(basic -> basic.realmName("Actuator"))
            .csrf(csrf -> csrf.disable()); // Stateless API

        return http.build();
    }

    // Main application security chain
    @Bean
    @Order(2)
    public SecurityFilterChain applicationSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/api/public/**").permitAll()
                .requestMatchers("/api/**").authenticated()
                .anyRequest().denyAll()
            )
            // Comprehensive security headers
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; script-src 'self'; style-src 'self'; img-src 'self' data:; font-src 'self'; frame-ancestors 'none'; form-action 'self'"))
                .frameOptions(frame -> frame.deny())
                .xssProtection(xss -> xss.block(true))
                .contentTypeOptions(contentType -> {})
                .referrerPolicy(referrer -> referrer
                    .policy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN))
                .permissionsPolicy(permissions -> permissions
                    .policy("geolocation=(), microphone=(), camera=()"))
            )
            .csrf(csrf -> csrf.ignoringRequestMatchers("/api/**"))
            .sessionManagement(session -> session
                .sessionFixation().newSession()
                .maximumSessions(1));

        return http.build();
    }

    @Bean
    public UserDetailsService actuatorUserDetailsService() {
        // In production, use external identity provider or secrets manager
        String actuatorPassword = System.getenv("ACTUATOR_PASSWORD");
        if (actuatorPassword == null || actuatorPassword.length() < 32) {
            throw new IllegalStateException(
                "ACTUATOR_PASSWORD must be set and at least 32 characters");
        }

        return new InMemoryUserDetailsManager(
            User.withUsername("actuator-admin")
                .password("{bcrypt}" + actuatorPassword)
                .roles("ACTUATOR_ADMIN")
                .build()
        );
    }
}
```

```java
import org.springframework.boot.actuate.info.InfoContributor;
import org.springframework.boot.actuate.info.Info;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Profile;
import org.springframework.core.env.Environment;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import jakarta.annotation.PostConstruct;
import java.util.Arrays;
import java.util.List;
import java.util.Map;

@Configuration
public class EnvironmentSecurityConfiguration {

    private static final Logger logger = LoggerFactory.getLogger(
        EnvironmentSecurityConfiguration.class);

    private final Environment environment;

    // Forbidden patterns that should never appear in production
    private static final List<String> FORBIDDEN_PRODUCTION_PROFILES = 
        Arrays.asList("dev", "development", "debug", "test", "local");

    private static final List<String> REQUIRED_PRODUCTION_SETTINGS = Arrays.asList(
        "ACTUATOR_PASSWORD",
        "DB_PASSWORD",
        "JWT_SECRET"
    );

    public EnvironmentSecurityConfiguration(Environment environment) {
        this.environment = environment;
    }

    @PostConstruct
    @Profile("production")
    public void validateProductionConfiguration() {
        String[] activeProfiles = environment.getActiveProfiles();

        // Check for forbidden profiles
        for (String profile : activeProfiles) {
            if (FORBIDDEN_PRODUCTION_PROFILES.contains(profile.toLowerCase())) {
                logger.error("SECURITY ALERT: Forbidden profile '{}' active in production", 
                    profile);
                throw new IllegalStateException(
                    "Production cannot run with profile: " + profile);
            }
        }

        // Verify required secrets are set
        for (String setting : REQUIRED_PRODUCTION_SETTINGS) {
            String value = System.getenv(setting);
            if (value == null || value.isEmpty()) {
                logger.error("SECURITY ALERT: Required setting '{}' not configured", 
                    setting);
                throw new IllegalStateException(
                    "Production requires setting: " + setting);
            }
        }

        // Verify debug is disabled
        if (Boolean.parseBoolean(environment.getProperty("debug", "false"))) {
            throw new IllegalStateException(
                "Debug mode cannot be enabled in production");
        }

        logger.info("Production security configuration validated successfully");
    }

    @Bean
    @Profile("production")
    public InfoContributor securityInfoContributor() {
        return builder -> builder.withDetail("security", Map.of(
            "actuator-authentication", "enabled",
            "debug-mode", "disabled",
            "security-headers", "enabled",
            "ssl", "required"
        ));
    }
}
```

