@Component
public class SecurityConfigurationValidator implements ApplicationRunner {

    private static final Logger logger = LoggerFactory.getLogger(
        SecurityConfigurationValidator.class);

    @Value("${server.error.include-stacktrace:never}")
    private String includeStacktrace;

    @Value("${management.endpoint.env.enabled:false}")
    private boolean envEndpointEnabled;

    @Value("${management.endpoint.heapdump.enabled:false}")
    private boolean heapdumpEnabled;

    @Override
    public void run(ApplicationArguments args) {
        List<String> violations = new ArrayList<>();

        if (!"never".equals(includeStacktrace)) {
            violations.add("Stack traces enabled in error responses");
        }
        if (envEndpointEnabled) {
            violations.add("Environment endpoint is enabled");
        }
        if (heapdumpEnabled) {
            violations.add("Heapdump endpoint is enabled");
        }

        if (!violations.isEmpty()) {
            String alert = "SECURITY VIOLATIONS DETECTED: " + 
                String.join(", ", violations);
            logger.error(alert);

            // Send alert to security monitoring
            securityAlertService.sendCriticalAlert(alert);

            // In strict mode, prevent startup
            if (Boolean.parseBoolean(System.getenv("STRICT_SECURITY_MODE"))) {
                throw new IllegalStateException(alert);
            }
        }
    }
