// SafeDebugInfo only exposes non-sensitive metrics
type SafeDebugInfo struct {
	AppVersion    string `json:"app_version"`
	GoVersion     string `json:"go_version"`
	NumGoroutines int    `json:"num_goroutines"`
	NumCPU        int    `json:"num_cpu"`
}

func main() {
