	// SECURE: Only register debug endpoints in development
	if config.Environment == "development" && config.DebugEnabled {
		log.Println("WARNING: Debug endpoints enabled (development mode)")
		registerDebugEndpoints(mux)
	}

	// Safe status endpoint for production monitoring
	mux.HandleFunc("/health", healthHandler)
	mux.HandleFunc("/", homeHandler)

	log.Fatal(http.ListenAndServe(":8080", mux))
