func registerDebugEndpoints(mux *http.ServeMux) {
	// Wrap all debug endpoints with authentication
	mux.HandleFunc("/debug/pprof/", debugAuthMiddleware(pprof.Index))
	mux.HandleFunc("/debug/pprof/cmdline", debugAuthMiddleware(pprof.Cmdline))
	mux.HandleFunc("/debug/pprof/profile", debugAuthMiddleware(pprof.Profile))
	mux.HandleFunc("/debug/pprof/symbol", debugAuthMiddleware(pprof.Symbol))
	mux.HandleFunc("/debug/pprof/trace", debugAuthMiddleware(pprof.Trace))
	mux.HandleFunc("/debug/info", debugAuthMiddleware(safeDebugInfoHandler))
