func debugAuthMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		token := r.Header.Get("X-Debug-Token")
		if token == "" || token != config.DebugToken {
			log.Printf("Unauthorized debug access attempt from %s", r.RemoteAddr)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}
		next(w, r)
	}
}

func safeDebugInfoHandler(w http.ResponseWriter, r *http.Request) {
	// Only expose safe, non-sensitive information
