<?php
// app/Exceptions/Handler.php - Custom error handler

namespace App\Exceptions;

use Illuminate\Foundation\Exceptions\Handler as ExceptionHandler;
use Illuminate\Support\Facades\Log;
use Throwable;

class Handler extends ExceptionHandler
{
    // Never expose these in error responses
    protected $dontFlash = [
        'password',
        'password_confirmation',
        'current_password',
        'credit_card',
        'cvv',
        'api_key',
    ];

    public function register(): void
    {
        $this->reportable(function (Throwable $e) {
            // Log detailed error for internal use
            Log::error('Application Error', [
                'exception' => get_class($e),
                'message' => $e->getMessage(),
                'file' => $e->getFile(),
                'line' => $e->getLine(),
                'trace' => $e->getTraceAsString(),
                'user_id' => auth()->id(),
                'url' => request()->fullUrl(),
                'ip' => request()->ip(),
                'user_agent' => request()->userAgent(),
            ]);
        });
    }

    public function render($request, Throwable $e)
    {
        // API requests get JSON response
        if ($request->expectsJson()) {
            return $this->renderApiError($e);
        }

        // In production, show custom error pages
        if (app()->environment('production')) {
            return $this->renderProductionError($e);
        }

        return parent::render($request, $e);
    }

    private function renderApiError(Throwable $e)
    {
        $status = method_exists($e, 'getStatusCode') 
            ? $e->getStatusCode() 
            : 500;

        // Generate error reference ID for support
        $errorId = uniqid('ERR-', true);

        Log::error("API Error [{$errorId}]", [
            'exception' => $e->getMessage()
        ]);

        return response()->json([
            'error' => true,
            'message' => $status === 500 
                ? 'An internal error occurred' 
                : $e->getMessage(),
            'error_id' => $errorId,
        ], $status);
    }

    private function renderProductionError(Throwable $e)
    {
        $status = method_exists($e, 'getStatusCode') 
            ? $e->getStatusCode() 
            : 500;

        $errorId = uniqid('ERR-', true);

        return response()->view('errors.generic', [
            'error_id' => $errorId,
            'status' => $status,
        ], $status);
    }
}
