@Configuration
@Profile("production")
public class ProductionSecurityConfig {

    @Bean
    public SecurityFilterChain actuatorSecurity(HttpSecurity http) throws Exception {
        http
            .requestMatcher(EndpointRequest.toAnyEndpoint())
            .authorizeRequests(requests -> requests
                // Public health check for load balancer
                .requestMatchers(EndpointRequest.to(HealthEndpoint.class)).permitAll()
                .requestMatchers(EndpointRequest.to(InfoEndpoint.class)).permitAll()
                // All other actuator endpoints require ACTUATOR_ADMIN role
                .anyRequest().hasRole("ACTUATOR_ADMIN")
            )
            .httpBasic();
        return http.build();
    }
}

@Configuration
@Profile("production")
public class ProductionErrorConfig {

    @Bean
    public ErrorAttributes errorAttributes() {
        return new DefaultErrorAttributes() {
            @Override
            public Map<String, Object> getErrorAttributes(
                    WebRequest request, ErrorAttributeOptions options) {
                // Remove all sensitive information in production
                Map<String, Object> attrs = super.getErrorAttributes(request, 
                    ErrorAttributeOptions.defaults());
                attrs.remove("trace");
                attrs.remove("message");
                attrs.remove("exception");
                attrs.remove("errors");
                // Add correlation ID for support
                attrs.put("correlationId", MDC.get("correlationId"));
                return attrs;
            }
        };
    }
}

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiError> handleAllExceptions(
            Exception ex, HttpServletRequest request) {

        String correlationId = MDC.get("correlationId");
        if (correlationId == null) {
            correlationId = UUID.randomUUID().toString();
            MDC.put("correlationId", correlationId);
        }

        // Log full details internally with structured logging
        logger.error("Unhandled exception [correlationId={}, path={}, method={}]",
            correlationId, request.getRequestURI(), request.getMethod(), ex);

        // Audit log for security monitoring
        auditLogger.warn("ERROR_OCCURRED correlationId={} clientIp={} path={} userAgent={}",
            correlationId,
            request.getRemoteAddr(),
            request.getRequestURI(),
            request.getHeader("User-Agent"));

        // Return sanitized response with correlation ID for support
        ApiError error = new ApiError(
            HttpStatus.INTERNAL_SERVER_ERROR.value(),
            "An unexpected error occurred. Reference: " + correlationId,
            correlationId
        );

        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ResponseEntity<ApiError> handleNotFound(
            ResourceNotFoundException ex, HttpServletRequest request) {

        String correlationId = MDC.get("correlationId");
        logger.info("Resource not found [correlationId={}, resource={}]",
            correlationId, ex.getResourceType());

        ApiError error = new ApiError(
            HttpStatus.NOT_FOUND.value(),
            "The requested resource was not found",
            correlationId
        );

        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }
}

public class ApiError {
    private int status;
    private String message;
    private String correlationId;
    private long timestamp;

    public ApiError(int status, String message, String correlationId) {
        this.status = status;
        this.message = message;
        this.correlationId = correlationId;
        this.timestamp = System.currentTimeMillis();
    }

    // Getters omitted for brevity
}
