      show-details: when_authorized
      show-components: when_authorized
    info:
      enabled: true
    prometheus:
      enabled: true
    metrics:
      enabled: true
  server:
    port: 8081  # Separate port for actuator
    address: 127.0.0.1  # Only accessible from localhost/internal
```

**Defense in Depth Layers**:

1. **Environment-based Configuration**:
```java
// Fail fast if critical security settings missing in production
@Configuration
@Profile("production")
public class ProductionStartupValidator implements ApplicationRunner {

    @Value("${server.error.include-stacktrace}")
    private String includeStacktrace;

    @Override
    public void run(ApplicationArguments args) {
        if (!"never".equals(includeStacktrace)) {
            throw new IllegalStateException(
                "SECURITY VIOLATION: Stack traces must be disabled in production!");
        }
        // Verify other security settings
    }
}
```

2. **Request Correlation and Tracing**:
```java
@Component
public class CorrelationIdFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request,
            HttpServletResponse response, FilterChain chain) 
            throws ServletException, IOException {

        String correlationId = request.getHeader("X-Correlation-ID");
        if (correlationId == null || correlationId.isEmpty()) {
            correlationId = UUID.randomUUID().toString();
        }

        MDC.put("correlationId", correlationId);
        response.setHeader("X-Correlation-ID", correlationId);

        try {
            chain.doFilter(request, response);
        } finally {
            MDC.clear();
        }
    }
}
```

3. **Security Headers**:
```java
@Configuration
public class SecurityHeadersConfig {

    @Bean
    @Profile("production")
    public SecurityFilterChain securityHeaders(HttpSecurity http) throws Exception {
        http
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; frame-ancestors 'none'"))
                .frameOptions(frame -> frame.deny())
                .httpStrictTransportSecurity(hsts -> hsts
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000))
                .contentTypeOptions(content -> {})
            );
        return http.build();
    }
}
```

**Additional Protections**:
- **Externalize secrets**: Use HashiCorp Vault, AWS Secrets Manager, or Kubernetes secrets - never hardcode credentials
- **Separate actuator network**: Run actuator on internal-only port/network, use service mesh for access control
- **Continuous monitoring**: Alert on unusual error rates, stack trace leakage in logs, or unauthorized actuator access
- **Security scanning**: Use tools like OWASP ZAP or Burp Suite to scan for exposed debug endpoints before deployment
- **Runtime protection**: Use RASP (Runtime Application Self-Protection) to detect and block information disclosure attacks
